public static boolean accept(String fName, String name, Version min, Version max) {
        if (fName.startsWith(name + "_") && fName.toLowerCase().endsWith(".jar")) {
            if (min == null || max == null)
                return true;
            int i = fName.indexOf("_");
            String versionStr = fName.substring(i + 1, fName.length() - 4);
            Version v = Version.createVersion(versionStr);
            if (v == null)
                return true;
            return v.compareTo(min) >= 0 && v.compareTo(max) < 0;
        }
        return false;
    }

public static boolean accept(String fName, String name, Version min, Version max) {
    boolean namePrefixMatches = fName.startsWith(name + "_");
    boolean isJar = fName.toLowerCase().endsWith(".jar");
    if (!namePrefixMatches || !isJar) {
        return false;
    }
    if (min == null || max == null) {
        return true;
    }
    int underscoreIdx = fName.indexOf("_");
    String versionStr = fName.substring(underscoreIdx + 1, fName.length() - 4);
    Version parsed = Version.createVersion(versionStr);
    if (parsed == null) {
        return true;
    }
    return parsed.compareTo(min) >= 0 && parsed.compareTo(max) < 0;
}

