public static int[] getTileNumber( final double lat, final double lon, final int zoom ) {
        int xtile = (int) Math.floor((lon + 180) / 360 * (1 << zoom));
        int ytile_osm = (int) Math.floor(
                (1 - Math.log(Math.tan(Math.toRadians(lat)) + 1 / Math.cos(Math.toRadians(lat))) / Math.PI) / 2 * (1 << zoom));
        if (xtile < 0)
            xtile = 0;
        if (xtile >= (1 << zoom))
            xtile = ((1 << zoom) - 1);
        if (ytile_osm < 0)
            ytile_osm = 0;
        if (ytile_osm >= (1 << zoom))
            ytile_osm = ((1 << zoom) - 1);
        return new int[]{zoom, xtile, ytile_osm};
    }

public static int[] getTileNumber(double lat, double lon, int zoom) {
    int maxTile = 1 << zoom;

    int xtile = (int) Math.floor((lon + 180) / 360 * maxTile);
    double latRad = Math.toRadians(lat);
    int ytile = (int) Math.floor(
            (1 - Math.log(Math.tan(latRad) + 1 / Math.cos(latRad)) / Math.PI) / 2 * maxTile);

    xtile = Math.max(0, Math.min(maxTile - 1, xtile));
    ytile = Math.max(0, Math.min(maxTile - 1, ytile));

    return new int[]{zoom, xtile, ytile};
}

public static int calculateBindLength(int bindCount) {
    int res = 0;
    int bindLen = 2;
    int maxBindsOfLen = 9;
    while (bindCount > 0) {
      int numBinds = Math.min(maxBindsOfLen, bindCount);
      bindCount -= numBinds;
      res += bindLen * numBinds;
      bindLen++;
      maxBindsOfLen *= 10;
    }
    return res;
  }

public static int calculateBindLength(int bindCount) {
    if (bindCount <= 0) {
        return 0;
    }
    int digits = String.valueOf(bindCount).length();
    int total = 0;
    int lowerBound = 1;
    for (int d = 1; d <= digits; d++) {
        int upperBound = (int) Math.min(bindCount, Math.pow(10, d) - 1);
        int count = upperBound - lowerBound + 1;
        total += count * (1 + d);
        lowerBound = upperBound + 1;
    }
    return total;
}

public static <K, V> Map<K, V> asHashMap(List<V> list, ListExtractor<K, V> extractor) {
        if (list == null || extractor == null || list.isEmpty()) {
            return Collections.<K, V>emptyMap();
        }
        Map<K, V> map = new LinkedHashMap<>(list.size());
        for (V node : list) {
            map.put(extractor.extractKey(node), extractor.extractValue(node));
        }
        return map;
    }

public static <K, V> Map<K, V> asHashMap(List<V> list, ListExtractor<K, V> extractor) {
    if (list == null || extractor == null || list.isEmpty()) {
        return Collections.emptyMap();
    }
    return list.stream().collect(Collectors.toMap(
        extractor::extractKey,
        extractor::extractValue,
        (existing, replacement) -> replacement,
        LinkedHashMap::new
    ));
}
